# Generated by google (gemini-2.5-flash)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'IMAGE_TAG', defaultValue: 'my-app:latest', description: 'Docker image tag (e.g., my-app:1.0.0)')
        string(name: 'REGISTRY_URL', defaultValue: 'myregistry.example.com/myorg', description: 'Docker registry URL (e.g., myregistry.example.com/myorg)')
    }

    stages {
        stage('Checkout') {
            steps {
                checkout scm
            }
        }

        stage('Build Docker Image') {
            steps {
                script {
                    def fullImageName = "${params.REGISTRY_URL}/${params.IMAGE_TAG}"
                    echo "Building Docker image: ${fullImageName}"
                    sh "docker build -t ${fullImageName} ."
                }
            }
        }

        stage('Push Docker Image') {
            steps {
                script {
                    def fullImageName = "${params.REGISTRY_URL}/${params.IMAGE_TAG}"
                    echo "Pushing Docker image: ${fullImageName}"
                    // NOTE: Ensure your Jenkins agent has Docker configured and is logged into the registry,
                    // or add a 'docker login' step here using 'withCredentials' if authentication is required.
                    // Example for login (replace 'docker-registry-credentials' with your actual Jenkins credential ID):
                    // withCredentials([usernamePassword(credentialsId: 'docker-registry-credentials', passwordVariable: 'DOCKER_PASSWORD', usernameVariable: 'DOCKER_USERNAME')]) {
                    //     sh "echo \"$DOCKER_PASSWORD\" | docker login -u \"$DOCKER_USERNAME\" --password-stdin ${params.REGISTRY_URL.split('/')[0]}"
                    // }
                    sh "docker push ${fullImageName}"
                }
            }
        }
    }
}